//
import { objectEntries, pick } from '../../utils/zcutils';

function findBestParser(name, as, _) {
    let { cache, parser } = _;

    let saved = cache.as[pick(name, 'zcUnNamed')];
    if (saved.length === 1) {
        return saved[0];
    }

    let filteredParser = saved.filter(
        _ =>
            _._as &&
            objectEntries(_._as)
                .map(_ => _[0])
                .indexOf(as) !== -1
    );
    if (filteredParser.length === 1) {
        return filteredParser[0];
    }

    return findByLevel(filteredParser, parser._level);
}

function findByLevel(parser, level) {
    if (!level) {
        return parser[0];
    }

    let has = parser.filter(_ => _._level.indexOf(level) === 0);
    if (has.length) {
        return has[0];
    }

    return findByLevel(parser, level.substr(0, level.length - 2));
}

export { findBestParser };
